<?php
if ( ! defined( 'ABSPATH' ) ) { exit; }
class VH360_Studio_Bible_Importer {
    public function create_job($user_id,$file,$meta){ if(empty($meta['permissionConfirmed'])){return new WP_Error('vh360_bible_permission_required',__('Confirm that you have permission to use this file.','videohub360-studio'),array('status'=>400));}$required=array('translationKey','name','abbreviation','language','sourceName','licenseName','datasetVersion');foreach($required as $k){if(empty($meta[$k]))return new WP_Error('vh360_bible_import_metadata_required',__('Bible translation metadata is required.','videohub360-studio'),array('status'=>400));} if(empty($file['tmp_name'])||!is_uploaded_file($file['tmp_name']))return new WP_Error('vh360_bible_upload_required',__('CSV file is required.','videohub360-studio'),array('status'=>400));$uploads=wp_upload_dir();$dir=trailingslashit($uploads['basedir']).'vh360-studio-bible';wp_mkdir_p($dir);$dest=$dir.'/'.wp_unique_filename($dir,sanitize_file_name($file['name'])); if(!move_uploaded_file($file['tmp_name'],$dest))return new WP_Error('vh360_bible_upload_failed',__('CSV upload failed.','videohub360-studio'),array('status'=>500)); global $wpdb;$jobs=VH360_Studio_Database::bible_import_jobs_table_name();$now=current_time('mysql');$key=sanitize_key($meta['translationKey']);$hash=hash_file('sha256',$dest);$wpdb->insert($jobs,array('user_id'=>absint($user_id),'translation_key'=>$key,'source_file'=>$dest,'source_hash'=>$hash,'status'=>'created','created_at'=>$now,'updated_at'=>$now,'error_message'=>wp_json_encode($this->sanitize_meta($meta))));$id=(int)$wpdb->insert_id;$wpdb->update($jobs,array('temporary_translation_key'=>'__vh360_import_'.$id),array('id'=>$id));return $this->get_job($id); }
    private function sanitize_meta($m){return array('translation_key'=>sanitize_key($m['translationKey']),'name'=>sanitize_text_field($m['name']),'abbreviation'=>sanitize_text_field($m['abbreviation']),'language'=>sanitize_text_field($m['language']),'source_name'=>sanitize_text_field($m['sourceName']),'source_url'=>esc_url_raw(isset($m['sourceUrl'])?$m['sourceUrl']:''),'license_name'=>sanitize_text_field($m['licenseName']),'license_url'=>esc_url_raw(isset($m['licenseUrl'])?$m['licenseUrl']:''),'attribution'=>sanitize_textarea_field(isset($m['attribution'])?$m['attribution']:''),'attribution_required'=>!empty($m['attributionRequired'])?1:0,'dataset_version'=>sanitize_text_field($m['datasetVersion']));}
    public function get_job($id){global $wpdb;$j=VH360_Studio_Database::bible_import_jobs_table_name();return $wpdb->get_row($wpdb->prepare("SELECT * FROM {$j} WHERE id=%d",absint($id)),ARRAY_A);}
    public function cancel_job($id){$job=$this->get_job($id); if(!$job)return false; global $wpdb;$wpdb->delete(VH360_Studio_Database::bible_verses_table_name(),array('translation_key'=>$job['temporary_translation_key'])); if(!empty($job['source_file'])&&file_exists($job['source_file']))wp_delete_file($job['source_file']); return (bool)$wpdb->update(VH360_Studio_Database::bible_import_jobs_table_name(),array('status'=>'cancelled','updated_at'=>current_time('mysql')),array('id'=>absint($id)));}
    public function process_batch($id,$limit=null){global $wpdb;$job=$this->get_job($id); if(!$job)return new WP_Error('vh360_bible_import_missing',__('Import job not found.','videohub360-studio'),array('status'=>404));$limit=min(1000,max(1,absint($limit?:apply_filters('vh360_studio_bible_import_batch_size',500))));$fh=fopen($job['source_file'],'r'); if(!$fh)return new WP_Error('vh360_bible_import_file_missing',__('Import file missing.','videohub360-studio'),array('status'=>500));$meta=json_decode($job['error_message'],true);$verses=VH360_Studio_Database::bible_verses_table_name();$now=current_time('mysql');$processed=$imported=$omitted=$failed=0;$books=array();$offset=(int)$job['byte_offset'];if($offset>0)fseek($fh,$offset); else { $header=fgetcsv($fh); if($header&&isset($header[0]))$header[0]=preg_replace('/^\xEF\xBB\xBF/','',$header[0]); }
        while($processed<$limit && ($row=fgetcsv($fh))!==false){$processed++; if(count($row)<4){$failed++;continue;} $book=VH360_Studio_Bible_Books::normalize_name($row[0]);$chap=absint($row[1]);preg_match('/^(\d+)([a-z]?)$/i',trim($row[2]),$vm);$verse=$vm?absint($vm[1]):0;$suffix=$vm?strtolower($vm[2]):'';$text=wp_check_invalid_utf8((string)$row[3]); if(!$book||$chap<1||$verse<1||strlen($text)>20000){$failed++;continue;} $status=trim($text)===''?'omitted':'present';$ok=$wpdb->replace($verses,array('translation_key'=>$job['temporary_translation_key'],'book_key'=>$book['key'],'book_name'=>$book['default_name'],'book_order'=>$book['order'],'chapter_number'=>$chap,'verse_number'=>$verse,'verse_suffix'=>$suffix,'verse_text'=>$text,'verse_status'=>$status,'created_at'=>$now,'updated_at'=>$now)); if($ok){$books[$book['key']]=true; if('omitted'===$status)$omitted++; else $imported++;}else{$failed++;}}
        $eof=feof($fh);$byte=ftell($fh);fclose($fh);$wpdb->query('START TRANSACTION');$wpdb->update(VH360_Studio_Database::bible_import_jobs_table_name(),array('status'=>$eof?($failed?'failed':'promoting'):'importing','byte_offset'=>$byte,'rows_processed'=>$job['rows_processed']+$processed,'rows_imported'=>$job['rows_imported']+$imported,'rows_omitted'=>$job['rows_omitted']+$omitted,'rows_failed'=>$job['rows_failed']+$failed,'book_count'=>max((int)$job['book_count'],count($books)),'updated_at'=>$now),array('id'=>$id));$wpdb->query('COMMIT'); if($eof && !$failed){return $this->promote($id);} return $this->get_job($id);}
    private function promote($id){global $wpdb;$job=$this->get_job($id);$meta=json_decode($job['error_message'],true);$v=VH360_Studio_Database::bible_verses_table_name();$t=VH360_Studio_Database::bible_translations_table_name();$now=current_time('mysql');$book_count=(int)$wpdb->get_var($wpdb->prepare("SELECT COUNT(DISTINCT book_key) FROM {$v} WHERE translation_key=%s",$job['temporary_translation_key']));$verse_count=(int)$wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM {$v} WHERE translation_key=%s AND verse_status='present'",$job['temporary_translation_key']));$wpdb->query('START TRANSACTION');$wpdb->delete($v,array('translation_key'=>$job['translation_key']));$wpdb->update($v,array('translation_key'=>$job['translation_key']),array('translation_key'=>$job['temporary_translation_key']));$meta['status']='installed';$meta['source_hash']=$job['source_hash'];$meta['verse_count']=$verse_count;$meta['book_count']=$book_count;$meta['imported_at']=$now;$meta['created_at']=$now;$meta['updated_at']=$now;$wpdb->replace($t,$meta);$wpdb->update(VH360_Studio_Database::bible_import_jobs_table_name(),array('status'=>'completed','completed_at'=>$now,'updated_at'=>$now,'book_count'=>$book_count),array('id'=>$id));$wpdb->query('COMMIT'); if(file_exists($job['source_file']))wp_delete_file($job['source_file']);VH360_Studio_Bible_Repository::clear_translation_cache($job['translation_key']);return $this->get_job($id);}
}
